import{_ as a}from"./chunks/cloudflare api token截图.cXTahxtC.js";import{_ as l}from"./chunks/查看全局令牌.BhcACLhK.js";import{_ as i,o as r,c as n,a2 as o}from"./chunks/framework.DnrXFDHb.js";const c=JSON.parse('{"title":"Cloudflare API Token","description":"","frontmatter":{},"headers":[],"relativePath":"tr-TR/Safety/cloudflare-api-token.md","filePath":"tr-TR/Safety/cloudflare-api-token.md","lastUpdated":1781962217000}'),d={name:"tr-TR/Safety/cloudflare-api-token.md"};function s(t,e,u,m,y,k){return r(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="cloudflare-api-token" tabindex="-1">Cloudflare API Token <a class="header-anchor" href="#cloudflare-api-token" aria-label="Permalink to &quot;Cloudflare API Token&quot;">​</a></h1><p>Cloudflare API kimlik bilgileri, dosyalar değiştikten sonra ImgBed&#39;in Cloudflare CDN önbelleğini temizlemesini sağlar.</p><p><img src="'+a+'" alt="Cloudflare API Token ayarları" loading="lazy"></p><h2 id="nereden-yapılandırılır" tabindex="-1">Nereden Yapılandırılır? <a class="header-anchor" href="#nereden-yapılandırılır" aria-label="Permalink to &quot;Nereden Yapılandırılır?&quot;">​</a></h2><p>Yönetim panelini açın, ardından şuraya gidin:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; Cloudflare API Token</span></span></code></pre></div><p>Şunları doldurmanız gerekir:</p><ul><li>Zone ID</li><li>Account email</li><li>API Key</li></ul><h2 id="bu-ayar-ne-ise-yarar" tabindex="-1">Bu Ayar Ne İşe Yarar? <a class="header-anchor" href="#bu-ayar-ne-ise-yarar" aria-label="Permalink to &quot;Bu Ayar Ne İşe Yarar?&quot;">​</a></h2><p>Cloudflare herkese açık görsel URL&#39;lerini önbelleğe alabilir.</p><p>Önbellek görsellerin daha hızlı sunulmasını sağlar; ancak bir dosyayı sildikten, engelledikten, değiştirdikten veya taşıdıktan sonra eski içerik bir süre görünmeye devam edebilir.</p><p>Cloudflare API kimlik bilgileri yapılandırıldıktan sonra ImgBed bu işlemler tamamlandığında ilgili Cloudflare önbelleğini temizlemeye çalışır.</p><p>Şu durumlarda kullanışlıdır:</p><ul><li>Bir görseli silip herkese açık bağlantının mümkün olduğunca hızlı çalışmayı bırakmasını istiyorsanız.</li><li>Bir görseli engelleyip ziyaretçilerin özgün dosyayı görmesini durdurmak istiyorsanız.</li><li>Aynı ada sahip bir dosyayı değiştirip ziyaretçilerin yeni sürümü daha hızlı görmesini istiyorsanız.</li><li>Dosyaları taşıyıp yeniden adlandırıyor ve eski yol önbelleğinin hızlı yenilenmesini istiyorsanız.</li><li>Herkese açık erişim kurallarını değiştirip public gallery veya random image önbelleğinin daha hızlı güncellenmesini istiyorsanız.</li></ul><h2 id="bos-bırakırsanız-ne-olur" tabindex="-1">Boş Bırakırsanız Ne Olur? <a class="header-anchor" href="#bos-bırakırsanız-ne-olur" aria-label="Permalink to &quot;Boş Bırakırsanız Ne Olur?&quot;">​</a></h2><p>ImgBed bu ayar olmadan da normal çalışır.</p><p>Tek fark, ImgBed&#39;in Cloudflare CDN önbelleğini aktif olarak temizlememesidir. Ziyaretçiler Cloudflare önbelleği doğal olarak sona erene kadar eski içeriği görmeye devam edebilir.</p><h2 id="zone-id-nasıl-bulunur" tabindex="-1">Zone ID Nasıl Bulunur? <a class="header-anchor" href="#zone-id-nasıl-bulunur" aria-label="Permalink to &quot;Zone ID Nasıl Bulunur?&quot;">​</a></h2><p>Zone ID, ImgBed alan adınızın kullandığı sitenin Cloudflare Zone ID değeridir.</p><ol><li>Cloudflare dashboard&#39;a giriş yapın.</li><li>ImgBed alan adınızı içeren siteyi açın.</li><li>Site overview sayfasında <code>Zone ID</code> değerini bulun.</li><li>ImgBed&#39;deki <code>Zone ID</code> alanına kopyalayın.</li></ol><p>Bu değer hesap ID&#39;si değil, site Zone ID değeridir.</p><h2 id="account-email" tabindex="-1">Account Email <a class="header-anchor" href="#account-email" aria-label="Permalink to &quot;Account Email&quot;">​</a></h2><p>Cloudflare&#39;a giriş yaparken kullandığınız e-posta adresini girin.</p><p>Aşağıda verdiğiniz API Key ile eşleşmelidir.</p><h2 id="api-key" tabindex="-1">API Key <a class="header-anchor" href="#api-key" aria-label="Permalink to &quot;API Key&quot;">​</a></h2><p>Cloudflare Global API Key değerini girin.</p><ol><li>Cloudflare dashboard&#39;a giriş yapın.</li><li>Profilinizi açın.</li><li>API Tokens sayfasına gidin.</li><li><code>Global API Key</code> değerini bulun.</li><li>Görüntüleyip kopyalayın.</li><li>ImgBed&#39;deki <code>API Key</code> alanına yapıştırın.</li></ol><p><img src="'+l+'" alt="Global API key görüntüleme" loading="lazy"></p><h2 id="ne-zaman-etkili-olur" tabindex="-1">Ne Zaman Etkili Olur? <a class="header-anchor" href="#ne-zaman-etkili-olur" aria-label="Permalink to &quot;Ne Zaman Etkili Olur?&quot;">​</a></h2><p>Alanları doldurduktan sonra ayarları kaydedin.</p><p>Bundan sonraki dosya değişikliklerinde Cloudflare önbelleği otomatik olarak temizlenmeye çalışılır. Geçmiş işlemler geriye dönük olarak temizlenmez. Bu ayarı yapmadan önce bir dosya sildiyseniz veya değiştirdiyseniz Cloudflare önbelleğinin sona ermesini bekleyin ya da Cloudflare üzerinden elle temizleyin.</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="zorunlu-mu" tabindex="-1">Zorunlu mu? <a class="header-anchor" href="#zorunlu-mu" aria-label="Permalink to &quot;Zorunlu mu?&quot;">​</a></h3><p>Hayır.</p><p>Alan adınız Cloudflare kullanmıyorsa veya CDN önbellek gecikmesi sizin için sorun değilse boş bırakabilirsiniz.</p><h3 id="yanlıs-kimlik-bilgileri-yuklemeyi-bozar-mı" tabindex="-1">Yanlış Kimlik Bilgileri Yüklemeyi Bozar mı? <a class="header-anchor" href="#yanlıs-kimlik-bilgileri-yuklemeyi-bozar-mı" aria-label="Permalink to &quot;Yanlış Kimlik Bilgileri Yüklemeyi Bozar mı?&quot;">​</a></h3><p>Genellikle hayır.</p><p>Yanlış kimlik bilgileri yalnızca ImgBed&#39;in Cloudflare önbelleğini temizlemesini engeller. Yükleme ve normal dosya erişimi çalışmaya devam etmelidir.</p><h3 id="silinen-gorsel-neden-hala-acılıyor" tabindex="-1">Silinen Görsel Neden Hâlâ Açılıyor? <a class="header-anchor" href="#silinen-gorsel-neden-hala-acılıyor" aria-label="Permalink to &quot;Silinen Görsel Neden Hâlâ Açılıyor?&quot;">​</a></h3><p>En yaygın neden Cloudflare&#39;ın eski dosyayı hâlâ önbellekte tutmasıdır.</p><p>Doğru Cloudflare API kimlik bilgileriyle ImgBed dosya silindiğinde ilgili URL önbelleğini temizler.</p><h3 id="dosyayı-degistirdikten-sonra-neden-hala-eski-gorseli-goruyorum" tabindex="-1">Dosyayı Değiştirdikten Sonra Neden Hâlâ Eski Görseli Görüyorum? <a class="header-anchor" href="#dosyayı-degistirdikten-sonra-neden-hala-eski-gorseli-goruyorum" aria-label="Permalink to &quot;Dosyayı Değiştirdikten Sonra Neden Hâlâ Eski Görseli Görüyorum?&quot;">​</a></h3><p>Bu da genellikle CDN önbelleğinden kaynaklanır.</p><p>Bu ayar yapılandırıldıktan sonra ImgBed aynı ada sahip dosya üzerine yazıldığında eski URL önbelleğini temizlemeye çalışır.</p>',44)])])}const g=i(d,[["render",s]]);export{c as __pageData,g as default};
